"use client"

import { useState } from "react"
import { Card, CardContent } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Search, ArrowUp, ArrowDown, Plus } from "lucide-react"

interface Security {
  id: string
  symbol: string
  name: string
  sector: string
  current_price: number
  previous_close: number
  market_cap: number
  volume: number
  last_updated: string
}

interface MarketDataGridProps {
  securities: Security[]
}

export function MarketDataGrid({ securities }: MarketDataGridProps) {
  const [searchTerm, setSearchTerm] = useState("")

  const filteredSecurities = securities.filter(
    (security) =>
      security.symbol.toLowerCase().includes(searchTerm.toLowerCase()) ||
      security.name.toLowerCase().includes(searchTerm.toLowerCase()),
  )

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat("en-IN", {
      style: "currency",
      currency: "INR",
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(value)
  }

  const formatVolume = (value: number) => {
    if (value >= 10000000) {
      return `${(value / 10000000).toFixed(2)}Cr`
    } else if (value >= 100000) {
      return `${(value / 100000).toFixed(2)}L`
    }
    return value.toLocaleString("en-IN")
  }

  const calculateChange = (current: number, previous: number) => {
    const change = current - previous
    const changePercent = (change / previous) * 100
    return { change, changePercent, isPositive: change >= 0 }
  }

  return (
    <div className="space-y-6">
      <Card>
        <CardContent className="pt-6">
          <div className="flex items-center justify-between gap-4">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-gray-400" />
              <Input
                placeholder="Search by symbol or name..."
                className="pl-10"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <Button className="gap-2">
              <Plus className="h-4 w-4" />
              Add to Watchlist
            </Button>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="border-b bg-gray-50">
                <tr>
                  <th className="p-4 text-left text-sm font-semibold text-gray-900">Symbol</th>
                  <th className="p-4 text-left text-sm font-semibold text-gray-900">Name</th>
                  <th className="p-4 text-left text-sm font-semibold text-gray-900">Sector</th>
                  <th className="p-4 text-right text-sm font-semibold text-gray-900">Price</th>
                  <th className="p-4 text-right text-sm font-semibold text-gray-900">Change</th>
                  <th className="p-4 text-right text-sm font-semibold text-gray-900">Volume</th>
                  <th className="p-4 text-right text-sm font-semibold text-gray-900">Market Cap</th>
                </tr>
              </thead>
              <tbody>
                {filteredSecurities.map((security) => {
                  const { change, changePercent, isPositive } = calculateChange(
                    Number(security.current_price),
                    Number(security.previous_close),
                  )

                  return (
                    <tr key={security.id} className="border-b hover:bg-gray-50">
                      <td className="p-4">
                        <span className="font-semibold text-blue-600">{security.symbol}</span>
                      </td>
                      <td className="p-4 text-sm text-gray-900">{security.name}</td>
                      <td className="p-4">
                        <Badge variant="outline" className="text-xs">
                          {security.sector}
                        </Badge>
                      </td>
                      <td className="p-4 text-right font-semibold">{formatCurrency(Number(security.current_price))}</td>
                      <td className="p-4 text-right">
                        <div
                          className={`flex items-center justify-end gap-1 font-medium ${isPositive ? "text-green-600" : "text-red-600"}`}
                        >
                          {isPositive ? <ArrowUp className="h-4 w-4" /> : <ArrowDown className="h-4 w-4" />}
                          <span>{Math.abs(changePercent).toFixed(2)}%</span>
                        </div>
                      </td>
                      <td className="p-4 text-right text-sm text-gray-600">{formatVolume(Number(security.volume))}</td>
                      <td className="p-4 text-right text-sm text-gray-600">
                        {formatCurrency(Number(security.market_cap))}
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>

      {filteredSecurities.length === 0 && (
        <Card>
          <CardContent className="py-12 text-center">
            <p className="text-gray-500">No securities found matching your search.</p>
          </CardContent>
        </Card>
      )}
    </div>
  )
}
